mapper.select:
select count(1)
from chat_conversation_member
where conversation_id = #{conversationId}
  and user_id = #{userId}

mapper.update:
update chat_conversation_member
set unread_count = unread_count + 1,
    archived = 0,
    updated_at = now()
where conversation_id = #{conversationId}
  and user_id = #{userId}

update chat_conversation_member
set unread_count = 0,
    last_read_at = now(),
    updated_at = now()
where conversation_id = #{conversationId}
  and user_id = #{userId}

update chat_conversation_member
set archived = #{archived},
    updated_at = now()
where conversation_id = #{conversationId}
  and user_id = #{userId}
